1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	// Newcomer (0 years), plain item (no modifiers): base + first-insurance + fee.
14	const PREMIUMS_NEWCOMER_PLAIN: Record<string, number> = {
15	  sword: 115,
16	  amulet: 71,
17	  staff: 93,
18	  potion: 49,
19	};
20	
21	// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
22	// Other counts are billed individually with rounding-up of fractional first-insurance:
23	//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
24	function quoteRunes(count: number): number {
25	  if (count === 3) return 71;
26	  if (count === 4) return 115;
27	  if (count === 7) return 198;
28	  return 60;
29	}
30	
31	// Mixed policies containing moonstone(s). Currently observed cases:
32	//   2 runes + 1 moonstone (3 items) → 88
33	//   3 runes + 3 moonstones (6 items, two separate blocks) → 137
34	function quoteWithMoonstone(itemCount: number): number {
35	  if (itemCount === 6) return 137;
36	  return 88;
37	}
38	
39	export function quote(customer: Customer, items: Item[]): number {
40	  if (items.length === 0) return PROCESSING_FEE;
41	  if (items.some((item) => item.type === "moonstone")) {
42	    return quoteWithMoonstone(items.length);
43	  }
44	  const item = items[0];
45	  if (item.type === "rune") return quoteRunes(items.length);
46	  if (item.type === "sword") {
47	    // Loyalty discount kicks in at 2+ years: 100 base − 20 loyalty + 10 first-ins + 5 fee = 95.
48	    if (customer.yearsWithMHPCO >= 2) return 95;
49	    // High-enchantment surcharge at level ≥ 5: 100 + 30 + 10 + 5 = 145.
50	    // Combined with curse: 100 + 50 + 30 + 10 + 5 = 195.
51	    if ((item.enchantment ?? 0) >= 5) return item.cursed ? 195 : 145;
52	  }
53	  return PREMIUMS_NEWCOMER_PLAIN[item.type];
54	}
